var e=[{id:`L2_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`내가…. 내가 전부 망쳐 버렸어.`,JPN:`私が……私が全部壊したの。`,ENG:`I... I ruined it all.`,TWN:`我……我毀了一切。`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`그로니아도…… 엄마의 삶도. 전부.`,JPN:`グロニアも……お母さんの人生も。全部。`,ENG:`Gronia... my mother's life. Everything.`,TWN:`格羅尼亞……還有媽媽的人生，這一切。`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`차라리, 죽어 버렸으면 좋을 텐데….`,JPN:`いっそ、死んじゃえばよかったのに……`,ENG:`If would've been better if I just died...`,TWN:`我不如死了算了……`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`어째서 살았던 거야. 왜 그 때 끝장을 내지 못했던 거냐고….`,JPN:`どうして生き残ったの。どうしてあの時終わらすことができなかったの……`,ENG:`Why was I alive? Why didn't I end it that day...?`,TWN:`為什麼當初沒有自我了斷，還活到現在……`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`윽…… 흐윽…… 큭……`,JPN:`うっ……ううっ……くっ……`,ENG:`Ngh... Hrgh... Kgh...`,TWN:`呃……嗚嗚……呃……`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`어……? 바람?`,JPN:`え……？　風？`,ENG:`Huh...? Wind?`,TWN:`嗯……？是風？`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`……중사?`,JPN:`……軍曹？`,ENG:`...Sergeant?`,TWN:`……中士？`},stage:{bg:`HARMONY2_10`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`여긴, 어떻게…….`,JPN:`どうやって、ここに……`,ENG:`How did you...?`,TWN:`你怎麼會在這裡……！`},stage:{bg:`HARMONY2_10`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`잔뜩 억지를 부렸어요. 레버넌트 씨.`,JPN:`いっぱい我がまま言っちゃいました。レヴナントさん。`,ENG:`I insisted on seeing you, Revenant.`,TWN:`我費了多大的勁才來的，亡靈。`},stage:{bg:`HARMONY2_10`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`전할 말이 있었거든요.`,JPN:`伝えたいことがあったから。`,ENG:`I have something I want to say to you.`,TWN:`因為我有些話想對你說。`},stage:{bg:`HARMONY2_10`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`전할 말이라니…. 나한테?`,JPN:`伝えたいことって……私に？`,ENG:`Something you want to say... to me?`,TWN:`有話……對我說？`},stage:{bg:`HARMONY2_10`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`네. 당신이 해 준 감사 인사, 굉장히 부담스러웠거든요.`,JPN:`はい。あなたからの感謝の言葉、すごく気が重かったんです。`,ENG:`Yes. Your words of gratitude made me feel really uncomfortable.`,TWN:`對，你之前和我道謝時說的話，讓我覺得很有壓力。`},stage:{bg:`HARMONY2_10`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L17_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`제 훈장이 허울이란 걸 아는데도, 레버넌트 씨는 저를 믿어 줬으니까요.`,JPN:`勲章が形だけだってことを知ってからも、レヴナントさんは私のことを信じ続けてくれたから。`,ENG:`You knew that my Medal of Honor was a lie, but you still believed in me, Revenant.`,TWN:`你明知我的勳章虛有其名，卻還是相信我。`},stage:{bg:`HARMONY2_10`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`HARMONY2_10`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`그래서….`,JPN:`だから……`,ENG:`So...`,TWN:`所以……`},stage:{bg:`HARMONY2_10`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L20_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`그래서 이번에는, 그 말에 걸맞은 일을 할 거예요.`,JPN:`だから今度は、その言葉に相応しいことをするつもりです。`,ENG:`So this time, I'm going to do something that's worthy of what you said to me.`,TWN:`所以這次，我要回應你的信任。`},stage:{bg:`HARMONY2_10`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`손을 잡아요, 레버넌트 씨. 여기서 나갈 거예요.`,JPN:`手を取ってください、レヴナントさん。ここから出ます。`,ENG:`Take my hand, Revenant. We're getting out of here.`,TWN:`抓住我的手，亡靈。我們要離開這裡。`},stage:{bg:`HARMONY2_07`,slots:{L:null,C:null,R:null}}}];export{e as default};